val generateDistReadme by tasks.registering(Sync::class) {
    from("README.txt") {
        filter<ReplaceTokens>(
            "tokens" to
                mapOf(
                    "project.version" to distVersion,
                    "version.elasticsearch" to elasticsearchVersion,
                ),
            "beginToken" to "\${",
            "endToken" to "}",
        )
    }
    into(layout.buildDirectory.dir("generated/dist/readme"))
}

val generateDistScripts by tasks.registering(Sync::class) {
    into(layout.buildDirectory.dir("generated/dist/scripts"))

    startupPrograms.forEach { (applicationName, mainClass) ->
        from("src/main/scripts/unixBinTemplate") {
            rename { applicationName }
            filter<ReplaceTokens>(
                "tokens" to
                    mapOf(
                        "LICENSE_HEADER" to "",
                        "ENV_SETUP" to "",
                        "REPO" to "lib",
                        "CLASSPATH" to "\$BASEDIR/config:\$BASEDIR/lib/*",
                        "ENDORSED_DIR" to "driver-lib",
                        "EXTRA_JVM_ARGUMENTS" to defaultJvmOpts.joinToString(" "),
                        "APP_NAME" to applicationName,
                        "MAINCLASS" to mainClass,
                        "APP_ARGUMENTS" to "",
                        "UNIX_BACKGROUND" to "",
                    ),
                "beginToken" to "@",
                "endToken" to "@",
            )
        }
        from("src/main/scripts/windowsBinTemplate") {
            rename { "$applicationName.bat" }
            filter<ReplaceTokens>(
                "tokens" to
                    mapOf(
                        "LICENSE_HEADER" to "",
                        "ENV_SETUP" to "",
                        "JAVA_BINARY" to "java",
                        "REPO" to "lib",
                        "CLASSPATH" to "%BASEDIR%\\config;%BASEDIR%\\lib\\*",
                        "ENDORSED_DIR" to "driver-lib",
                        "EXTRA_JVM_ARGUMENTS" to defaultJvmOpts.joinToString(" "),
                        "APP_NAME" to applicationName,
                        "MAINCLASS" to mainClass,
                        "APP_ARGUMENTS" to "",
                    ),
                "beginToken" to "#",
                "endToken" to "#",
            )
        }
    }

    doLast {
        destinationDir.resolve(".")
            .walkTopDown()
            .filter { it.isFile && !it.name.endsWith(".bat") }
            .forEach { it.setExecutable(true, false) }
    }
}

val copyOpenApiYaml by tasks.registering(Sync::class) {
    from("../zeebe/gateway-protocol/src/main/proto/v2") {
        include("**/*.yaml")
    }
    into(layout.buildDirectory.dir("generated/dist/openapi/v2"))
}

val assembleDist by tasks.registering(Sync::class) {
    dependsOn(tasks.named("jar"), generateDistReadme, generateDistScripts, copyOpenApiYaml)
    duplicatesStrategy = DuplicatesStrategy.EXCLUDE
    into(distDirectory)

    from(generateDistScripts) {
        into("bin")
    }
    from("src/main/config") {
        into("config")
    }
    from(copyOpenApiYaml) {
        into("config/openapi/v2")
    }
    from(tasks.named<Jar>("jar")) {
        into("lib")
    }
    from(
        {
            configurations.runtimeClasspath.get().filter {
                it.isFile &&
                    !it.name.startsWith("ojdbc") &&
                    !it.name.startsWith("mysql-connector-j")
            }
        }
    ) {
        into("lib")
    }
    from(rootProject.file("licenses"))
    from(rootProject.file("NOTICE.txt"))
    from(generateDistReadme)

    doLast {
        destinationDir.resolve("bin")
            .walkTopDown()
            .filter { it.isFile && !it.name.endsWith(".bat") }
            .forEach { it.setExecutable(true, false) }
    }
}

val distTar by tasks.registering(Tar::class) {
    dependsOn(assembleDist)
    compression = Compression.GZIP
    archiveBaseName.set(distName)
    archiveVersion.set(distVersion)
    archiveExtension.set("tar.gz")
    destinationDirectory.set(layout.buildDirectory.dir("distributions"))

    from(assembleDist) {
        into("$distName-$distVersion")
    }
}

val distZip by tasks.registering(Zip::class) {
    dependsOn(assembleDist)
    archiveBaseName.set(distName)
    archiveVersion.set(distVersion)
    destinationDirectory.set(layout.buildDirectory.dir("distributions"))

    from(assembleDist) {
        into("$distName-$distVersion")
    }
}

